var customStrategies = {};
async function loadCustomStrategies(path2) {
  let files = [];
  try {
    files = await readdir(path2);
  } catch (error) {
    logger.warn(
      `Failed to load custom strategies from path "${path2}". Ensure the directory exists. Error: ${error.message}`
    );
  }
  for (const file of files) {
    if (!file.endsWith(".mjs")) {
      logger.warn(`Skipping file "${file}" because it is not an ES Module. Use .mjs extension instead.`);
      continue;
    }
    const strategyName = file.replace(/\.mjs$/, "");
    const { default: strategy } = await import(join(path2, file));
    customStrategies[strategyName] = strategy;
    logger.info(`Loaded custom strategy "${strategy.displayName || strategy.name}" from file "${file}"`);
  }
  return customStrategies;
}

