function findStrategy(strategyName) {
  const predefinedStrategyFn = templates_exports[strategyName];
  const customStrategyFn = customStrategies[strategyName];
  const strategyFn = predefinedStrategyFn || customStrategyFn;
  if (!strategyFn) {
    throw new Error(
      `Strategy "${strategyFn}" does not exists. Use one of predefined strategies: ${strategiesNames(templates_exports)}, or custom strategies: ${strategiesNames(customStrategies) || "<NO STRATEGIES>"}.`
    );
  }
  return {
    strategyFn,
    isCustom: !!customStrategyFn
  };
}
async function createBot({ ctx: ctx2, input }) {
  const { exchangeAccountId, data } = input;
  const exchangeAccount2 = await xprisma.exchangeAccount.findUnique({
    where: {
      id: exchangeAccountId,
      owner: {
        id: ctx2.user.id
      }
    }
  });
  if (!exchangeAccount2) {
    throw new TRPCError({
      message: "Exchange Account doesn't exists",
      code: "NOT_FOUND"
    });
  }
  let strategy;
  try {
    strategy = findStrategy(data.template);
  } catch (err) {
    throw new TRPCError({
      message: `Strategy ${data.template} not found`,
      code: "NOT_FOUND"
    });
  }
  const parsed = strategy.strategyFn.schema.safeParse(data.settings);
  if (!parsed.success) {
    throw new TRPCError({
      message: `Invalid strategy params: ${parsed.error.message}`,
      code: "PARSE_ERROR"
    });
  }
  const bot = await xprisma.bot.custom.create({
    data: {
      ...data,
      settings: JSON.stringify(data.settings),
      type: "Bot",
      exchangeAccount: {
        connect: {
          id: exchangeAccount2.id
        }
      },
      owner: {
        connect: {
          id: ctx2.user.id
        }
      }
    },
    include: { exchangeAccount: true }
  });
  await eventBus.emit("onBotCreated", bot);
  return bot;
}
