async function backtest({ ctx: ctx2, input }) {
  const { exchangeAccountId, symbol, settings, timeframe, template, startDate, endDate } = input;
  const exchangeAccount2 = await xprisma.exchangeAccount.findUnique({ where: { id: exchangeAccountId } });
  if (!exchangeAccount2) {
    throw new TRPCError({
      message: "Exchange Account doesn't exists",
      code: "NOT_FOUND"
    });
  }
  let strategy;
  try {
    strategy = findStrategy(template);
  } catch (err) {
    throw new TRPCError({
      message: `Strategy ${template} not found`,
      code: "NOT_FOUND"
    });
  }
  const parsed = strategy.strategyFn.schema.safeParse(settings);
  if (!parsed.success) {
    throw new TRPCError({
      message: `Invalid strategy params: ${parsed.error.message}`,
      code: "PARSE_ERROR"
    });
  }
  const ccxtExchange = exchangeCodeMapCCXT[exchangeAccount2.exchangeCode];
  const exchange = new pro[ccxtExchange]();
  const botConfig = {
    id: 0,
    symbol,
    exchangeCode: exchangeAccount2.exchangeCode,
    settings,
    timeframe
  };
  const backtesting = new Backtesting({ botConfig, botTemplate: strategy.strategyFn });
  return new Promise((resolve) => {
    const candles = [];
    const candleProvider = new CCXTCandlesProvider({
      exchange,
      symbol,
      timeframe,
      startDate,
      endDate
    });
    candleProvider.on("candle", (candle2) => candles.push(candle2));
    candleProvider.on("done", async () => {
      console.log(`Fetched ${candles.length} candlesticks`);
      const report = await backtesting.run(candles);
      resolve({
        result: report
      });
    });
    candleProvider.emit("start");
  });
}
