async function calcHighLowPrice(exchangeCode, currencyPair) {
  const exchange = exchangeProvider.fromCode(exchangeCode);
  const { price } = await exchange.getMarketPrice({
    symbol: currencyPair
  });
  const highPrice = price + price * 0.3;
  const lowPrice = price - price * 0.3;
  return { highPrice, lowPrice };
}
async function getFormOptions2({ input }) {
  const { symbolId } = input;
  const { exchangeCode, currencyPairSymbol } = decomposeSymbolId(symbolId);
  const { highPrice, lowPrice } = await calcHighLowPrice(
    exchangeCode,
    currencyPairSymbol
  );
  return {
    highPrice,
    lowPrice
  };
}
