// ../../packages/trpc/src/routers/private/cron/sync-closed-orders/handler.ts
async function syncClosedOrders({ ctx: _ }) {
  const exchangeAccounts = await xprisma.exchangeAccount.findMany();
  for (const exchangeAccount2 of exchangeAccounts) {
    const processor = new ExchangeAccountProcessor(exchangeAccount2);
    const { affectedBotsIds } = await processor.syncOrders();
    for (const botId of affectedBotsIds) {
      const bot = await BotProcessing.fromId(botId);
      await bot.process();
      await bot.placePendingOrders();
    }
  }
  return {
    ok: true
  };
}

