async function bootstrapPlatform() {
  const exchangeAccounts = await xprisma.exchangeAccount.findMany();
  logger.info(`\u{1F3DB}\uFE0F  Loaded ${exchangeAccounts.length} exchange account(s)`);
  const bot = await xprisma.bot.custom.findFirst({
    where: {
      label: "default"
    },
    include: { exchangeAccount: true }
  });
  logger.info(`\u{1F916} Default bot: ${bot ? bot.label : "none"}`);
  const platform = new Platform(exchangeAccounts);
  await platform.bootstrap();
  return platform;
}

